{
  "name": "Weatherization Assistance Program (WAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Household income must meet DOE WAP guidelines (typically 200% of federal poverty level or lower, varying by household size and income sources); exact dollar amounts available via county providers or CSD's DOE WAP Income Eligibility Guidelines page. Priority for elderly, disabled, households with young children, or greatest need. Contact local provider for precise table as it may vary by factors like energy use.[1][5]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["Legal resident of California", "Named on energy bill (some regions)", "Homeowner or renter", "Household meets energy usage or priority criteria (e.g., vulnerable populations like elderly)"]
  },
  "benefits": {
    "type": "service",
    "value": "Free installation of energy efficiency measures including insulation (ceiling/floor), repair/replacement of heating/AC, water heater, refrigerator, microwave, stove, doors, windows (glass only), free digital thermostats, weatherstripping, LED bulbs, shade screens, smoke/CO detectors. Whole-home assessment to reduce energy costs and improve health/safety.[1][2][4]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local service provider via CSD (https://www.csd.ca.gov/Pages/Residential-Energy-Efficiency.aspx)", "Call regional hotlines e.g., CSET Weatherization Hotline: 1-844-224-1316", "Call county agency for application (e.g., San Joaquin HSA)", "Download/print application from local agency website", "Pick up in-person at HSA/office", "Mail request for application"],
    "processing_time": "Varies by region; emergency appointments for disconnect notices within 1-2 days in some areas (e.g., LA).[3]",
    "waitlist": "Possible due to prioritization and funding; contact local provider for status.",
    "forms": ["Intake application (local agency-specific, e.g., with HEAP application in some areas)", "DOE WAP application via local provider"],
    "documents": ["Proof of income for all household members (last 4 weeks, pay stubs, benefit letters)", "Most recent electric/gas/propane bill", "Proof of legal residency/ID", "Social Security cards", "Utility bills/receipts for all energy sources"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered through local community-based providers by county/region.",
    "regional_variations": "Delivery varies by local provider (e.g., San Joaquin HSA vs. CSET in Tulare/Kings; LA County via 211LA); different hotlines, offices, languages (e.g., Spanish), specific services, wait times.[1][2][3][4]",
    "offices_or_providers": ["CSD local service providers statewide", "San Joaquin County Human Services Agency", "CSET (Tulare/Kings)", "211 LA providers"]
  },
  "official_source": "https://www.csd.ca.gov/Pages/Residential-Energy-Efficiency.aspx",
  "gotchas": ["Must contact local provider for exact eligibility/income (varies by income sources, not just table)", "Priority-based (elderly prioritized but not guaranteed)", "Services once per eligibility period (e.g., every 12 months in some related programs)", "Renter requires landlord approval (implied)", "Not emergency bill pay—focuses on weatherization", "Home must qualify via assessment (e.g., age 5+ years in similar ESA)"],
  "data_shape_notes": "Administered statewide via local providers with priority tiers for vulnerable (elderly); income at DOE guidelines with regional verification; no fixed statewide form/hotline—must find county provider"
}

{
  "name": "Health Insurance Counseling & Advocacy Program (HICAP)",
  "eligibility": {
    "age": null,
    "income_limits": "No income limits; services are free for all Medicare beneficiaries and their families regardless of income.",
    "asset_limits": "No asset limits; no financial eligibility requirements.",
    "other_requirements": ["Eligible for Medicare (includes those 65+ or younger with disability receiving Medicare)", "Soon-to-be eligible for Medicare", "Family members, friends, or representatives of Medicare beneficiaries"]
  },
  "benefits": {
    "type": "service|advocacy",
    "value": "Free, unbiased one-on-one counseling on Medicare benefits (Parts A, B, C, D), supplemental plans (Medigap), prescription drug plans, Medicare Advantage plans (HMOs, PPOs), Medicare Savings Programs, long-term care insurance, appeals, billing issues, claim denials, fraud/abuse; assistance with applications, forms, comparisons of plans, resolving complaints; community education and presentations.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": ["Statewide toll-free phone: 800-434-0222", "Local HICAP offices by county (e.g., Orange County: 714-560-0424; Riverside/San Bernardino/Inyo/Mono: 909-256-8369; Kern County: 661-868-1000 or 800-434-0222; Santa Clara: contact Sourcewise at 408-350-3245; Ventura: contact VCAAA)", "Online registration forms on local provider sites (e.g., coasc.org for specific counties, mysourcewise.com for Santa Clara)", "In-person at local Aging & Adult Services offices (e.g., Kern County: 5357 Truxtun Ave., Bakersfield)"],
    "processing_time": "Contact to schedule appointment; no formal processing time specified, typically responsive via phone or online registration.",
    "waitlist": null,
    "forms": ["No specific statewide form number; local registration sections or screening questions for appointments/volunteers; counselors assist with Medicare-related forms (e.g., Medicare Savings Program applications)"],
    "documents": ["No documents required for initial counseling; bring Medicare card, insurance details, bills/EOBs for appeals or specific issues if applicable"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available statewide in California via local providers; must contact local HICAP for county-specific service.",
    "regional_variations": "Delivered through different local agencies/area agencies on aging by county/region (e.g., Council on Aging for Orange/San Bernardino/Riverside/Inyo/Mono; Sourcewise for Santa Clara; Kern County Aging and Adult Services; Ventura County AAA); phone numbers, offices, and contact methods vary by county; no differences in core services.",
    "offices_or_providers": ["California Department of Aging (state oversight)", "Local examples: Council on Aging (Orange et al.), Sourcewise (Santa Clara), Kern County Aging and Adult Services, Ventura County AAA"]
  },
  "official_source": "https://www.aging.ca.gov/hicap/",
  "gotchas": ["Not an insurance sales program—counselors do not sell, endorse, or recommend specific commercial products; volunteers cannot be licensed agents/brokers/financial planners", "Services are counseling/education only, not direct financial aid or healthcare provision", "Must contact local HICAP for your county, not all have online forms", "Part of national SHIP network; for out-of-state, use SHIP locator"],
  "data_shape_notes": "no income/asset test; statewide but county-administered with local providers and contacts; services fixed and free for all Medicare-eligible"
}

{
  "name": "Family Caregiver Support Program",
  "eligibility": {
    "age": "Caregivers: 18+; Care recipients: 60+ or any age with Alzheimer’s/related disorders; Older relative caregivers: 55+[1]",
    "income_limits": "No income requirements[1]",
    "asset_limits": "No asset limits or requirements mentioned[1]",
    "other_requirements": ["Informal/unpaid caregivers providing care to specified groups", "Adult family members or other informal caregivers for individuals 60+ or with Alzheimer’s/related disorders", "Older relatives (55+) caring for children <18 or adults 18-59 with disabilities", "Verification of age, residency, relationship, and care recipient condition may be required regionally (e.g., LA County)[1][3]"]
  },
  "benefits": {
    "type": "service",
    "value": "Caregiver assessments and support plans; Caregiver training; Respite care; Counseling; Support groups; Supplemental services; Information and assistance; Assistive devices; Home modifications; Registries of independent care workers; Limited assistance with supplies/services. No fixed dollar amounts or hours statewide; services based on needs and funding availability[1][3]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone: Call 1-800-510-2020 to reach local provider (statewide multipurpose senior services line)[3]", "In-person or phone intake with local Area Agency on Aging (AAA) or contracted California Caregiver Resource Center (CCRC)[1][3]", "Contact local AAA for your county (administered locally)[1]"],
    "processing_time": "Not specified statewide; intake and eligibility process with assigned provider[3]",
    "waitlist": "Services based on available funding; potential limits regionally (e.g., consumable supplies limited per participant in LA County)[3]",
    "forms": ["No specific statewide form named; complete intake/eligibility process locally[3]"],
    "documents": ["Verification of caregiver age and residency", "Verification of care recipient age (60+) and condition", "Proof of relationship and residency for older relative caregivers", "Consent for services involving medical info[3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Administered through 33 Area Agencies on Aging (AAAs); some AAAs contract with California Caregiver Resource Centers (CCRCs)[1]",
    "regional_variations": "Services, providers, wait times, and verification processes vary by AAA/county (e.g., LA County specifics on documents and limits)[1][3][8]",
    "offices_or_providers": ["Local Area Agencies on Aging (AAAs) statewide; some contract with CCRCs[1]"]
  },
  "official_source": "https://www.aging.ca.gov/Providers_and_Partners/Area_Agencies_on_Aging/Family_Caregiver_Support/Program_Narrative_and_Fact_Sheets/[1]",
  "gotchas": ["Not a paid caregiver program—provides support services to unpaid informal caregivers, not stipends or wages[1]", "Administered locally by AAAs, so contact local office for exact services/availability; funding-limited[1][3]", "VA program [2] and Medicaid self-direction programs [4][5][7] are separate—not this OAA Title III-E FCSP[1]", "Older relative caregivers have specific criteria (non-parents for children)[1]", "Reassessments annual or as needed; no fixed service limits but funding-based[3]"],
  "data_shape_notes": "No income/asset test; administered via 33 local AAAs with regional service variations and funding limits; OAA Title III-E federal program (code 3900100) state-implemented[1]"
}

{
  "name": "Legal Services for Seniors (via AAAs)",
  "eligibility": {
    "age": 60,
    "income_limits": "No income limits; available regardless of income level[3].",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["California resident", "Services targeted to those with economic, social, or legal needs[6]", "Often prioritized for low-income or vulnerable seniors, though not strictly required[1][2]"]
  },
  "benefits": {
    "type": "service",
    "value": "Legal advice, consultations, advocacy, and representation for issues including housing, consumer fraud, elder abuse, Social Security, SSI, Medicare, Medi-Cal, age discrimination, pensions, nursing homes, protective services, conservatorships, public benefits, debt collection, simple wills, guardianships, advanced healthcare directives[2][3][4][5][6]. Examples: free 30-minute attorney consultation[1]; in-home appointments for homebound[4].",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Contact local Area Agency on Aging (AAA) by county via https://aging.ca.gov/Programs_and_Services/Find_Services_in_My_County/ [3]", "Examples: San Francisco/Marin - (415) 989-1616 or online at sfbar.org/lris/senior-legal-services/ [1]; San Mateo - (650) 558-0915 [4]; SF Legal Assistance to Elderly - (415) 538-3333 [5]", "In-person, phone, or online intake depending on local provider"],
    "processing_time": "Not specified; initial intake often by phone with subsequent appointments scheduled as needed[5].",
    "waitlist": "Not mentioned; may vary by local demand.",
    "forms": ["No specific statewide form; local intake processes apply."],
    "documents": ["Not explicitly listed; prepare proof of residency, age, and details of legal issue."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Delivered through 39 local Senior Legal Services Projects via 33 Area Agencies on Aging (AAAs), one per service area/county[2].",
    "regional_variations": "Varies by AAA/provider: different offices, subcontractors, specific services, phone numbers, and hours (e.g., SF Bar vs. San Mateo Legal Aid)[1][4][5].",
    "offices_or_providers": ["Local AAAs; find by county at aging.ca.gov[3]"]
  },
  "official_source": "https://aging.ca.gov/Providers_and_Partners/Legal_Services/Legal_Services_Overview/[2]",
  "gotchas": ["Not a single centralized program—must contact specific local AAA, leading to variations in services and access[2][3]", "No strict income test, but prioritized for greatest needs; high-demand areas may have informal wait times[6]", "Primarily civil legal matters; not criminal defense", "Some providers limited to specific counties (e.g., SF/Marin[1])"],
  "data_shape_notes": "Decentralized via local AAAs with no uniform income/asset test; services and access vary significantly by county/provider; targeted to economic/social needs despite open eligibility[2][3][6]"
}

{
  "name": "Caregiver Resource Centers (CRC)",
  "eligibility": {
    "age": null,
    "income_limits": "No specific income limits, asset limits, or financial tests mentioned; open to families and caregivers statewide without stated dollar thresholds[3][4][6]",
    "asset_limits": "No asset limits or exclusions detailed; program focuses on support services rather than financial aid programs with asset tests[3][4]",
    "other_requirements": ["Caregivers of adults with chronic, debilitating conditions including dementia, Alzheimer’s, stroke, Parkinson’s, Huntington’s, multiple sclerosis, traumatic brain injury (TBI), or similar cognitive/disabling disorders[3][4][6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Specialized information and referral; family consultation and care planning; respite care (financial assistance for in-home support, adult day care, short-term/weekend care, transportation); short-term counseling (individual, family, group); support groups (online/in-person); professional training workshops; legal/financial consultation (Powers of Attorney, Advance Directives, estate planning, conservatorships); education workshops on cognitive disorders, dementia, long-term care, stress management. No fixed dollar amounts or hours specified; respite provides financial assistance but amounts not detailed[3][4]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Contact local CRC by phone, website, or email (11 centers cover all counties; examples: Inland CRC (909) 514-1404 or (800) 675-6694, www.inlandcaregivers.org; statewide network at www.caregivercalifornia.org; LA CRC at losangelescrc.usc.edu[4][6][7][8]", "In-person or online support groups/consultations via local centers[3][4]"],
    "processing_time": "Not specified; services like consultations and referrals available immediately upon contact[3]",
    "waitlist": "No waitlist mentioned; serves thousands annually with direct access[3][4]",
    "forms": ["No specific forms named; intake via consultation with trained staff[3]"],
    "documents": ["No documents specified; needs assessment during family consultation[3]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; every county covered by one of 11 nonprofit centers[4][6][8]",
    "regional_variations": "Services delivered through 11 regional nonprofit centers with local phone numbers, websites, and offices; may differ in delivery but core services consistent statewide. Administered by California Department of Aging as of July 2022[3][4][6][7][8]",
    "offices_or_providers": ["11 nonprofit centers covering all counties, e.g., Inland Caregiver Resource Center (Inyo, Mono, Riverside, San Bernardino), Los Angeles CRC, others via www.caregivercalifornia.org[4][6][7][8]"]
  },
  "official_source": "https://www.aging.ca.gov/ (DHCS redirects here for CRC info as of July 2022)[3]",
  "gotchas": ["Not a paid caregiver program or direct compensation (compare to IHSS/Medi-Cal for wages); focuses on support/respite for unpaid family caregivers; no financial eligibility tests but targeted to specific conditions like dementia/stroke; must contact local center as no central application[1][3][4][5][6]", "Respite is financial assistance, not unlimited hours/dollars—assessed per case[3]", "Admin now under Dept. of Aging, not DHCS[3]"],
  "data_shape_notes": "Network of 11 regional nonprofit centers covering all counties; no income/asset tests; condition-specific for cognitive/chronic illnesses; services include targeted respite funding without fixed amounts; find local provider by county via central site"
}
